import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProjectDetails.css';

function ProjectDetails() {
  const { id } = useParams();
  const [project, setProject] = useState(null);
  const [userRole, setUserRole] = useState('');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProject();
    getUserRole();
  }, [id]);

  const getUserRole = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUserRole(response.data.role);
    } catch (error) {
      console.error('Error fetching user role:', error);
    }
  };

  const fetchProject = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get(`http://127.0.0.1:8000/api/projects/${id}/`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProject(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching project:', error);
      setLoading(false);
    }
  };

  if (loading) return <div className="loading">Loading...</div>;
  if (!project) return <div className="not-found">Project not found</div>;

  // Clean client name
  const cleanClientName = project.client_name ? project.client_name.replace(/_/g, ' ') : '';

  return (
    <div className="container">
      <button className="back-btn" onClick={() => navigate('/projects')}>
        ← Back to Projects
      </button>
      
      <h2>{project.title}</h2>
      
      <div className="project-detail-card">
        <div className="details-grid">
          {/* Label - Value pairs in proper grid */}
          <span className="detail-label">Description:</span>
          <span className="detail-value">{project.description}</span>
          
          <span className="detail-label">Skills Required:</span>
          <span className="detail-value">{project.skills_required}</span>
          
          <span className="detail-label">Budget:</span>
          <span className="detail-value budget-value">₹{project.budget_min} - ₹{project.budget_max}</span>
          
          <span className="detail-label">Duration:</span>
          <span className="detail-value">{project.duration_days} days</span>
          
          <span className="detail-label">Status:</span>
          <span className="detail-value">{project.status}</span>
          
          <span className="detail-label">Posted by:</span>
          <span className="detail-value">{cleanClientName}</span>
          
          <span className="detail-label">Posted on:</span>
          <span className="detail-value">{new Date(project.created_at).toLocaleDateString()}</span>
        </div>
      </div>

      {userRole === 'FREELANCER' && (
        <button 
          className="apply-btn"
          onClick={() => navigate(`/proposals/create/${id}`)}
        >
          Apply for this Project
        </button>
      )}
    </div>
  );
}

export default ProjectDetails;
